{
  "verses": [
    {
      "n": 4,
      "column": "left",
      "text": "Un tee Egipteri aprakke\nwiſſus Birnidſimtus / ko tas\nKUNGS winnu Starpâ bij no-\nfittis / tas KUNGS bij arridsan\nSohdibu turrejis prett winnu\nDeeween.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Rad tee Israëka Behrni no\nRaëmses bija iſgahjuſchi / tad\napmettahs tee Sukotâ.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Un tee iſgahje no Sufo-\nta / un apmettahs Eetamâ / kas\nTuksnefes Gallâ irr.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Un tee iſgahje no Eetama /\nun greeſahs us Pt-Akirotu / kas\nprett Baal-Zewonu irr / un ap-\nmettahs prett Migdolu.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Un tee iſgahje no Akirotas/\nun gabje widdn zaur to Juheu\nus to Tuksnefi/ un staigaja treijo\nDeenn Zelta- Gahjumês Eeta-\nma Tuksneti / un apmettahs\nMahra.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Un tee iſgahje no Mahras/\nun nahze us Eelimu / un Eelima\nbija diwipadesmitis Awoscht / un\nfeptindeſinitis Palina-Kohki / un\ntee apmettahs tur.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Un tee iſgahje no Eelima/\nun apmettahs pee Needru-Juhras.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Un tee iſgahje no Needru-\nJuhras/ un apmettahs tai Tuks-\nneti Sin.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Un tee iſgahje no tahs\nTuksneses Sin / un apmettahs\nDawkâ.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Un tee iſgahje no Daw-\nkas/ un apmettahs Ahlusâ.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Un tee iſgahje no Ahlusas/\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Tad iſgahje tee no Ra-\nwideein/un apmettahs eekſch tahs\nTuksnefes Sinai.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Un tee iſgahje no tahs Tuks-\nnefes Sinai / un apmettahs pe-\nteem Eekahroſchanas-Kappeein.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Un tee iſgahje no teem\nEekahroſchanas-Kappeem/un ap-\nmettahs Azerotâ.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un tee iſgahje no Azero-\nta / un apmettahs Ritina.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un tee iſgahje no Rit-\nmas/ un apmettahs Rimmon-\nParezâ.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un tee iſgahje xo Rim-\nmon - Pareza / un apmettahe\nLibnâ.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Un tee iſgahje no Libnas/\nun apmettahs Rifâ.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Un tee iſgahje no Rifias/\nun apmettahs Keelataâ.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un tee iſgahje no Keela-\ntas/ un apmettahs pee Sahwe-\nra Kalna.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un tee iſgahje no Sah-\nweza Kalna / un apmettahs A-\nradâ.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un tee iſgahje no Ara-\ndas/ un apmettahs Makeelotaâ.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Un tee iſgahje no Makee-\nlotas/ un apmettahs Taataâ.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Un tee iſgahje no Taatas/\nun apmettahs Tahrakaâ.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Un tee iſgahje no Tahra-\nkas/ un apmettahs Mitkâ.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Un tee iſgahje no Mit-\nkas/ un apmettahs Afmona.\n"
    }
  ],
